head.script:
//
tailwind.config = {
  theme: {
    extend: {
      fontFamily: {
        sans: ['Inter', 'sans-serif'],
        display: ['Space Grotesk', 'sans-serif'],
      },
      colors: {
        primary: '#6b705c', // Sage Green
        accent: '#cb997e',  // Warm Terracotta
        charcoal: '#1d1d1f' // Apple Black
      },
      screens: {
        '3xl': '1920px',
        '4xl': '2560px',
        '5xl': '3840px'
      }
    }
  }
}
//

head.b:skin:
/* Apple-style Smooth Parallax Custom Core Styles */
html {
  scroll-behavior: smooth;
}

body {
  font-family: 'Inter', sans-serif;
  background-color: #fbfbf9;
  color: #1d1d1f;
  overflow-x: hidden;
  margin: 0;
  padding: 0;
  transition: background-color 0.3s ease;
}

/* 4K & Ultra-Wide Display Optimizations - Proportional scaling to prevent horizontal stretching */
@media (min-width: 1920px) {
  .max-w-7xl { max-width: 1360px !important; }
  .max-w-6xl { max-width: 1200px !important; }
  .max-w-5xl { max-width: 1080px !important; }
  .max-w-4xl { max-width: 900px !important; }
  body { font-size: 16px; }
}
@media (min-width: 2560px) {
  .max-w-7xl { max-width: 1440px !important; }
  .max-w-6xl { max-width: 1280px !important; }
  .max-w-5xl { max-width: 1120px !important; }
  .max-w-4xl { max-width: 960px !important; }
  body { font-size: 18px; }
}
@media (min-width: 3840px) {
  .max-w-7xl { max-width: 1600px !important; }
  .max-w-6xl { max-width: 1400px !important; }
  .max-w-5xl { max-width: 1200px !important; }
  .max-w-4xl { max-width: 1000px !important; }
  body { font-size: 22px; }
}

/* Floating Keyframe Animation */
@keyframes float-y {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-14px); }
}
.animate-float {
  animation: float-y 6s ease-in-out infinite;
}
.animate-float-delay {
  animation: float-y 6s ease-in-out infinite;
  animation-delay: 3s;
}

/* Out-of-sync Gentle Bobbing/Swaying Animations for Dashboard Cards */
@keyframes bob-gentle-1 {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
}
@keyframes bob-gentle-2 {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-7px); }
}
@keyframes bob-gentle-3 {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-12px); }
}
.animate-bob-1 {
  animation: bob-gentle-1 5.5s ease-in-out infinite;
}
.animate-bob-2 {
  animation: bob-gentle-2 6.5s ease-in-out infinite;
}
.animate-bob-3 {
  animation: bob-gentle-3 6s ease-in-out infinite;
}

/* Error Shake Animation */
@keyframes shake {
  0%, 100% { transform: translateX(0); }
  25% { transform: translateX(-5px); }
  75% { transform: translateX(5px); }
}
.shake-element {
  animation: shake 0.25s ease-in-out 2;
}

/* Organic Floating Background Glow Blobs */
@keyframes drift-blob-1 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  33% { transform: translate(120px, -80px) scale(1.2); }
  66% { transform: translate(-60px, 100px) scale(0.85); }
}
@keyframes drift-blob-2 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  50% { transform: translate(-100px, 120px) scale(1.25); }
}
@keyframes drift-blob-3 {
  0%, 100% { transform: translate(0px, 0px) scale(1); }
  40% { transform: translate(80px, 90px) scale(0.9); }
}
.animate-drift-1 {
  animation: drift-blob-1 25s ease-in-out infinite;
}
.animate-drift-2 {
  animation: drift-blob-2 30s ease-in-out infinite;
}
.animate-drift-3 {
  animation: drift-blob-3 28s ease-in-out infinite;
}

/* 3D Isometric Cards with Preservation of Depth and custom rotation */
.isometric-container {
  perspective: 1500px;
}
.isometric-card {
  transform: rotateX(20deg) rotateY(-12deg) rotateZ(3deg);
  transform-style: preserve-3d;
  transition: all 1s cubic-bezier(0.16, 1, 0.3, 1);
}
.isometric-card:hover {
  transform: rotateX(10deg) rotateY(-4deg) rotateZ(0deg) translateY(-12px);
  box-shadow: 0 50px 100px -20px rgba(107, 112, 92, 0.22), 0 30px 60px -15px rgba(203, 153, 126, 0.14);
}
.isometric-card-right {
  transform: rotateX(20deg) rotateY(12deg) rotateZ(-3deg);
  transform-style: preserve-3d;
  transition: all 1s cubic-bezier(0.16, 1, 0.3, 1);
}
.isometric-card-right:hover {
  transform: rotateX(10deg) rotateY(4deg) rotateZ(0deg) translateY(-12px);
  box-shadow: 0 50px 100px -20px rgba(203, 153, 126, 0.22), 0 30px 60px -15px rgba(107, 112, 92, 0.14);
}

/* Glassmorphism navigation */
.glass-nav {
  background: rgba(251, 251, 249, 0.8);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid rgba(0, 0, 0, 0.05);
}

/* Standard Blogger Layout Overrides to Hide Default Widgets and Navbar */
#navbar-iframe, .navbar, .header-outer, .sidebar-outer, .footer-outer, .post-share-buttons {
  display: none !important;
  visibility: hidden !important;
}

.status-msg-wrap {
  display: none !important;
}

/* Interactive animations & custom visual effects */
.hero-gradient {
  background: radial-gradient(circle at 50% 50%, rgba(107, 112, 92, 0.08) 0%, transparent 60%);
}

.apple-card-hover {
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}
.apple-card-hover:hover {
  transform: translateY(-10px) scale(1.02);
  box-shadow: 0 40px 80px -20px rgba(0,0,0,0.1);
}

/* Scroll animations */
.scroll-reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 1.2s cubic-bezier(0.16, 1, 0.3, 1), transform 1.2s cubic-bezier(0.16, 1, 0.3, 1);
}
.scroll-reveal.active {
  opacity: 1;
  transform: translateY(0);
}

/* Custom Input Range styling */
input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 6px;
  background: #e5e1d8;
  border-radius: 999px;
  outline: none;
}
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: #6b705c;
  cursor: pointer;
  transition: transform 0.1s ease;
  box-shadow: 0 2px 6px rgba(0,0,0,0.15);
}
input[type="range"]::-webkit-slider-thumb:hover {
  transform: scale(1.2);
}

/* Premium shadow effects & Glows */
.shadow-premium {
  box-shadow: 0 30px 60px -15px rgba(107, 112, 92, 0.12), 0 15px 30px -10px rgba(203, 153, 126, 0.08);
}
.shadow-premium-hover {
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}
.shadow-premium-hover:hover {
  transform: translateY(-8px) scale(1.01);
  box-shadow: 0 40px 80px -20px rgba(107, 112, 92, 0.18), 0 20px 40px -15px rgba(203, 153, 126, 0.12);
}

/* Standardized typography and prose style for Blogger pages */
.post-body-content p, .prose p {
  margin-bottom: 1.5rem;
  line-height: 1.8;
}
.post-body-content h2, .prose h2 {
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 700;
  font-size: 1.5rem;
  color: #1d1d1f;
  margin-top: 2.5rem;
  margin-bottom: 1rem;
}
.post-body-content ul, .prose ul {
  list-style-type: disc;
  padding-left: 1.5rem;
  margin-bottom: 1.5rem;
}
.post-body-content li, .prose li {
  margin-bottom: 0.5rem;
}

body.script:
//
// Range Slider bindings
const rangeSessions = document.getElementById('range-sessions');
const rangePrice = document.getElementById('range-price');
const rangeRent = document.getElementById('range-rent');
const chkBaby = document.getElementById('chk-baby');

// Values display elements
const valSessions = document.getElementById('val-sessions');
const valPrice = document.getElementById('val-price');
const valRent = document.getElementById('val-rent');

// Result displays
const resGross = document.getElementById('res-gross');
const resRent = document.getElementById('res-rent');
const resBaby = document.getElementById('res-baby');
const resNet = document.getElementById('res-net');

function updateCalculations() {
  if (!rangeSessions) return;
  const sessions = parseInt(rangeSessions.value);
  const price = parseInt(rangePrice.value);
  const rent = parseInt(rangeRent.value);
  const hasBaby = chkBaby ? chkBaby.checked : false;
  const babyFee = 150; // standard hourly babysitter fee

  // Update text displays
  if (valSessions) valSessions.textContent = sessions + " Seans";
  if (valPrice) valPrice.textContent = "₺" + price.toLocaleString('tr-TR');
  if (valRent) valRent.textContent = "₺" + rent.toLocaleString('tr-TR');

  // Math calculations
  const gross = sessions * price;
  const totalRent = sessions * rent;
  const totalBaby = hasBaby ? (sessions * babyFee) : 0;
  const net = gross - totalRent - totalBaby;

  // Update result displays
  if (resGross) resGross.textContent = "₺" + gross.toLocaleString('tr-TR');
  if (resRent) resRent.textContent = "₺" + totalRent.toLocaleString('tr-TR');

  if (resBaby) {
    resBaby.textContent = "₺" + totalBaby.toLocaleString('tr-TR');
    if (!hasBaby) {
      resBaby.style.textDecoration = 'line-through';
      resBaby.style.opacity = '0.5';
    } else {
      resBaby.style.textDecoration = 'none';
      resBaby.style.opacity = '1';
    }
  }

  if (resNet) resNet.textContent = "₺" + net.toLocaleString('tr-TR');
}

if (rangeSessions) {
  rangeSessions.addEventListener('input', updateCalculations);
  rangePrice.addEventListener('input', updateCalculations);
  rangeRent.addEventListener('input', updateCalculations);
  if (chkBaby) chkBaby.addEventListener('change', updateCalculations);
  updateCalculations();
}

// Smooth Scroll Reveal - Apple Presentation Technique
const revealElements = document.querySelectorAll('.scroll-reveal');
function handleScrollReveal() {
  revealElements.forEach(el => {
    const rect = el.getBoundingClientRect();
    const elementVisibleHeight = 100;
    if (rect.top < window.innerHeight - elementVisibleHeight) {
      el.classList.add('active');
    }
  });
}

// Apple-style Parallax Scrolling & Lerp Effect
const parallaxWrappers = document.querySelectorAll('.parallax-wrapper');
const heroBg = document.getElementById('hero-parallax-bg');

// Lerp state
let targetScrollY = 0;
let currentScrollY = 0;
const lerpStrength = 0.08; // Buttery smooth momentum coefficient
let isRequestingFrame = false;

function updateParallax() {
  // Lerp logic for buttery smooth inertial scroll
  currentScrollY += (targetScrollY - currentScrollY) * lerpStrength;

  if (heroBg) {
    // Shift hero background circle gradient
    heroBg.style.transform = `translateY(${currentScrollY * 0.3}px)`;
  }

  parallaxWrappers.forEach(el => {
    const speed = parseFloat(el.getAttribute('data-speed')) || 0;
    // Translate elements based on speed and current lerped scroll
    el.style.transform = `translateY(${currentScrollY * speed}px)`;
  });

  // Continue the frame loop if the difference is noticeable
  if (Math.abs(targetScrollY - currentScrollY) > 0.1) {
    requestAnimationFrame(updateParallax);
  } else {
    currentScrollY = targetScrollY;
    isRequestingFrame = false;
  }
}

window.addEventListener('scroll', () => {
  targetScrollY = window.scrollY;
  handleScrollReveal();
  if (!isRequestingFrame) {
    isRequestingFrame = true;
    requestAnimationFrame(updateParallax);
  }
}, { passive: true });

// Initial trigger to show elements already in viewport
document.addEventListener('DOMContentLoaded', () => {
  targetScrollY = window.scrollY;
  currentScrollY = window.scrollY;
  handleScrollReveal();
  updateParallax();
});

// Live mockup list animator (Component Loop Animation)
const mockupSessions = [
  { initials: 'MY', name: 'Melis Yılmaz (Face to Face)', details: 'Seans Süresi: 50 Dk | Oda 3', fee: 1800, status: 'Ödendi', statusClass: 'text-emerald-700 bg-emerald-50', color: 'bg-[#6b705c]/10 text-[#6b705c]' },
  { initials: 'OD', name: 'Ömer Demir (Online Seans)', details: 'Seans Süresi: 50 Dk | Google Meet', fee: 1500, status: 'Beklemede', statusClass: 'text-amber-700 bg-amber-50', color: 'bg-[#cb997e]/10 text-[#cb997e]' },
  { initials: 'CK', name: 'Canan Kaya (Çocuk Terapisi)', details: 'Seans Süresi: 50 Dk | Oda 1', fee: 2000, status: 'Ödendi', statusClass: 'text-emerald-700 bg-emerald-50', color: 'bg-slate-900/10 text-slate-900' },
  { initials: 'BC', name: 'Berk Can (Çift Terapisi)', details: 'Seans Süresi: 80 Dk | Oda 4', fee: 2500, status: 'Ödendi', statusClass: 'text-emerald-700 bg-emerald-50', color: 'bg-[#6b705c]/10 text-[#6b705c]' },
  { initials: 'SB', name: 'Selin Başar (EMDR Seansı)', details: 'Seans Süresi: 50 Dk | Google Meet', fee: 1900, status: 'Beklemede', statusClass: 'text-amber-700 bg-amber-50', color: 'bg-[#cb997e]/10 text-[#cb997e]' }
];

let currentSessionIndex = 2; // start by replacing/adding
const mockupListContainer = document.querySelector('#hero-section .space-y-3');

// Stats variables in mockup (not simulator!)
const mockStatGross = document.querySelector('#hero-section .grid > div:nth-child(1) span:nth-child(2)');
const mockStatRent = document.querySelector('#hero-section .grid > div:nth-child(2) span:nth-child(2)');
const mockStatNet = document.querySelector('#hero-section .grid > div:nth-child(3) span:nth-child(2)');

let activeGrossVal = 32400;
let activeRentVal = 5400;
let activeNetVal = 27000;

function animateMockupComponent() {
  if (!mockupListContainer) return;

  const itemToInsert = mockupSessions[currentSessionIndex];

  // Create new element with fade class
  const newCard = document.createElement('div');
  newCard.className = 'flex items-center justify-between p-3.5 bg-white border border-slate-200/60 rounded-xl hover:border-slate-300 transition-all opacity-0 -translate-y-4 duration-500';
  newCard.innerHTML = `
    <div class='flex items-center gap-3'>
      <div class='w-9 h-9 rounded-full ${itemToInsert.color} flex items-center justify-center text-xs font-bold'>${itemToInsert.initials}</div>
      <div>
        <span class='text-xs font-bold text-slate-800 block'>${itemToInsert.name}</span>
        <span class='text-[10px] text-slate-500 font-mono'>${itemToInsert.details}</span>
      </div>
    </div>
    <div class='text-right'>
      <span class='text-xs font-bold text-slate-800 block'>₺${itemToInsert.fee.toLocaleString('tr-TR')}</span>
      <span class='text-[9px] font-semibold ${itemToInsert.statusClass} px-2.5 py-0.5 rounded-full'>${itemToInsert.status}</span>
    </div>
  `;

  // Remove the last child of list container and insert the new one at the top
  if (mockupListContainer.children.length >= 2) {
    const lastChild = mockupListContainer.lastElementChild;
    if (lastChild) {
      lastChild.classList.add('opacity-0', 'translate-y-4');
      setTimeout(() => {
        if (lastChild.parentNode === mockupListContainer) {
          mockupListContainer.removeChild(lastChild);
        }
        mockupListContainer.insertBefore(newCard, mockupListContainer.firstChild);
        // Trigger transition
        setTimeout(() => {
          newCard.classList.remove('opacity-0', '-translate-y-4');
        }, 50);
      }, 300);
    }
  } else {
    mockupListContainer.insertBefore(newCard, mockupListContainer.firstChild);
    setTimeout(() => {
      newCard.classList.remove('opacity-0', '-translate-y-4');
    }, 50);
  }

  // Update the mock stats nicely
  activeGrossVal += itemToInsert.fee;
  // Assume a rent fee of 350 for face to face (or Google Meet is 0!)
  const rentFeeForSession = itemToInsert.details.includes('Google Meet') ? 0 : 350;
  activeRentVal += rentFeeForSession;
  activeNetVal = activeGrossVal - activeRentVal;

  // Smooth value transitions in UI
  if (mockStatGross) mockStatGross.textContent = "₺" + activeGrossVal.toLocaleString('tr-TR');
  if (mockStatRent) mockStatRent.textContent = "₺" + activeRentVal.toLocaleString('tr-TR');
  if (mockStatNet) mockStatNet.textContent = "₺" + activeNetVal.toLocaleString('tr-TR');

  // Loop to next item
  currentSessionIndex = (currentSessionIndex + 1) % mockupSessions.length;
}

// Run component loop every 4 seconds
setInterval(animateMockupComponent, 4000);

// Isometric Dashboard Showcase Animator
let isoTotalRent = 23450;
const isoTotalRentEl = document.getElementById('iso-total-rent');
const isoActivityContainer = document.getElementById('iso-activity-container');
const isoRoomsContainer = document.getElementById('iso-rooms-container');
const isoTherapistsContainer = document.getElementById('iso-therapists-container');

const isoActivities = [
  {
    title: 'Takvim Senkronize Edildi',
    desc: 'Dr. Elif Nazlı takvimi üzerinden 1 yeni seans algılandı.',
    time: 'Şimdi',
    icon: 'calendar',
    iconColor: 'bg-emerald-50 text-emerald-600',
    action: 'room-3-occupied',
    rentAdded: 350
  },
  {
    title: 'Ödeme Alındı',
    desc: 'Psk. Melis Demir seans kira ödemesi (₺350) onaylandı.',
    time: 'Şimdi',
    icon: 'check-circle',
    iconColor: 'bg-[#6b705c]/10 text-[#6b705c]',
    action: 'rent-increment',
    rentAdded: 350
  },
  {
    title: 'iCal Güncellendi',
    desc: 'Dr. Özgür Can takvimi ile iCal takvimi senkronize edildi.',
    time: 'Şimdi',
    icon: 'refresh-cw',
    iconColor: 'bg-[#cb997e]/10 text-accent',
    action: 'room-1-occupied',
    rentAdded: 350
  }
];

let currentIsoActivityIndex = 0;

function animateIsometricDashboard() {
  if (!isoActivityContainer || !isoTotalRentEl) return;

  const act = isoActivities[currentIsoActivityIndex];

  // Update total rent with animate-pulse look
  isoTotalRent += act.rentAdded;
  isoTotalRentEl.textContent = "₺" + isoTotalRent.toLocaleString('tr-TR');
  isoTotalRentEl.classList.add('text-accent');
  setTimeout(() => {
    isoTotalRentEl.classList.remove('text-accent');
  }, 800);

  // Create new activity log element
  const logDiv = document.createElement('div');
  logDiv.className = 'flex items-start gap-3 p-3 bg-slate-50 border border-slate-100 rounded-xl opacity-0 -translate-x-4 transition-all duration-500';
  logDiv.innerHTML = `
    <div class='p-1.5 rounded-lg ${act.iconColor} mt-0.5 shrink-0'>
      <i data-lucide='${act.icon}'></i>
    </div>
    <div class='text-left'>
      <span class='text-[11px] font-bold text-slate-800 block'>${act.title}</span>
      <p class='text-[9px] text-slate-500 leading-normal'>${act.desc}</p>
      <span class='text-[8px] font-mono text-slate-400 mt-1 block'>${act.time}</span>
    </div>
  `;

  // Insert and trigger transition
  isoActivityContainer.insertBefore(logDiv, isoActivityContainer.firstChild);
  setTimeout(() => {
    logDiv.classList.remove('opacity-0', '-translate-x-4');
    // Initialize lucide on the newly injected icon
    if (window.lucide) {
      window.lucide.createIcons();
    }
  }, 50);

  // Prune old activities if more than 2
  if (isoActivityContainer.children.length > 2) {
    const last = isoActivityContainer.lastElementChild;
    if (last) {
      last.classList.add('opacity-0', 'translate-x-4');
      setTimeout(() => {
        if (last.parentNode === isoActivityContainer) {
          isoActivityContainer.removeChild(last);
        }
      }, 500);
    }
  }

  // Live changes to the rooms or therapists to make it look active
  if (currentIsoActivityIndex === 0 && isoRoomsContainer) {
    // Toggle Room 2 to occupied for a moment!
    const r2 = isoRoomsContainer.children[1];
    if (r2) {
      r2.innerHTML = `
        <div class='flex items-center gap-3'>
          <div class='w-8 h-8 rounded-lg bg-emerald-50 flex items-center justify-center text-[10px] font-bold text-emerald-700'>O2</div>
          <div>
            <span class='text-xs font-bold text-slate-800 block'>Oda 2 (Oyun Terapisi)</span>
            <span class='text-[9px] text-slate-400 font-medium'>Psk. Damla Su (Özel Seans)</span>
          </div>
        </div>
        <span class='text-[9px] font-bold text-emerald-700 bg-emerald-50 px-2.5 py-0.5 rounded-full'>Dolu</span>
      `;
      r2.classList.add('border-emerald-200', 'bg-emerald-50/10');
      setTimeout(() => {
        r2.innerHTML = `
          <div class='flex items-center gap-3'>
            <div class='w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-[10px] font-bold text-slate-400'>O2</div>
            <div>
              <span class='text-xs font-bold text-slate-800 block'>Oda 2 (Oyun Terapisi)</span>
              <span class='text-[9px] text-slate-400 font-medium'>Boş - Rezervasyon Yok</span>
            </div>
          </div>
          <span class='text-[9px] font-bold text-slate-400 bg-slate-100 px-2.5 py-0.5 rounded-full'>Boş</span>
        `;
        r2.classList.remove('border-emerald-200', 'bg-emerald-50/10');
      }, 3500);
    }
  }

  currentIsoActivityIndex = (currentIsoActivityIndex + 1) % isoActivities.length;
}

// Run isometric animator every 4.5 seconds
setInterval(animateIsometricDashboard, 4500);

// ==========================================
// Interactive Room Permission & Booking Simulator
// ==========================================
const permissions = {
  melis: { std: true, play: true },
  ozgur: { std: true, play: false }
};

let bookingTimeout = null;

window.togglePermission = function(therapist, type) {
  const active = !permissions[therapist][type];
  permissions[therapist][type] = active;

  const btnId = `btn-perm-${therapist}-${type}`;
  const btn = document.getElementById(btnId);
  if (btn) {
    if (active) {
      btn.className = 'px-2.5 py-1 text-[10px] font-bold rounded-lg border transition-all bg-emerald-50 text-emerald-700 border-emerald-200 flex items-center gap-1 cursor-pointer';
      btn.innerHTML = `<span>✓ ${type === 'std' ? 'Standart' : 'Oyun Ter.'}</span>`;
    } else {
      btn.className = 'px-2.5 py-1 text-[10px] font-bold rounded-lg border transition-all bg-red-50 text-red-700 border-red-200 flex items-center gap-1 cursor-pointer';
      btn.innerHTML = `<span>✗ ${type === 'std' ? 'Standart' : 'Oyun Ter.'}</span>`;
    }
  }

  const therapistName = therapist === 'melis' ? 'Psk. Melis Demir' : 'Dr. Özgür Can';
  const typeName = type === 'std' ? 'Standart Terapi Odası' : 'Çocuk Oyun Terapi Odası';
  updateSimConsole(`GÜNCELLEME: ${therapistName} için ${typeName} yetkisi ${active ? 'AÇILDI' : 'KAPATILDI'}.`, 'text-[#cb997e]');
}

window.simulateBooking = function(therapist, type) {
  if (bookingTimeout) clearTimeout(bookingTimeout);
  resetSimRooms();

  const therapistName = therapist === 'melis' ? 'Psk. Melis Demir' : 'Dr. Özgür Can';
  const roomNum = type === 'std' ? 1 : 2;
  const roomEl = document.getElementById(`sim-room-${roomNum}`);
  const badgeEl = document.getElementById(`sim-room-${roomNum}-badge`);
  const descEl = document.getElementById(`sim-room-${roomNum}-desc`);

  updateSimConsole(`iCal BAĞLANTISI: ${therapistName} takviminden seans rezervasyon isteği geldi... (#Oda${roomNum})`, 'text-slate-200');

  const isAuthorized = permissions[therapist][type];

  setTimeout(() => {
    if (isAuthorized) {
      updateSimConsole(`ONAYLANDI: ${therapistName} yetki kontrolü başarılı. Seans Oda ${roomNum}'ye işlendi.`, 'text-emerald-400');

      if (roomEl && badgeEl && descEl) {
        roomEl.className = 'p-3.5 bg-emerald-50/20 border border-emerald-200 rounded-2xl flex flex-col justify-between h-[85px] transition-all scale-102';
        badgeEl.className = 'text-[9px] px-1.5 py-0.5 bg-emerald-500 text-white font-bold rounded';
        badgeEl.textContent = 'Dolu';
        descEl.className = 'text-[10px] text-emerald-800 font-semibold';
        descEl.textContent = `${therapistName} (Seans Aktif)`;
      }

      bookingTimeout = setTimeout(() => {
        resetSimRooms();
      }, 4500);

    } else {
      updateSimConsole(`BLOKE EDİLDİ: ${therapistName} bu oda tipi için yetkilendirilmemiş! Talep reddedildi.`, 'text-red-400');

      if (roomEl && badgeEl && descEl) {
        roomEl.className = 'p-3.5 bg-red-50/20 border border-red-200 rounded-2xl flex flex-col justify-between h-[85px] transition-all shake-element';
        badgeEl.className = 'text-[9px] px-1.5 py-0.5 bg-red-500 text-white font-bold rounded';
        badgeEl.textContent = 'ENGELLENDİ';
        descEl.className = 'text-[10px] text-red-800 font-semibold';
        descEl.textContent = 'Yetkisiz Erişim Teşebbüsü';
      }

      bookingTimeout = setTimeout(() => {
        resetSimRooms();
      }, 4500);
    }
  }, 800);
}

function resetSimRooms() {
  const r1 = document.getElementById('sim-room-1');
  const r1b = document.getElementById('sim-room-1-badge');
  const r1d = document.getElementById('sim-room-1-desc');

  const r2 = document.getElementById('sim-room-2');
  const r2b = document.getElementById('sim-room-2-badge');
  const r2d = document.getElementById('sim-room-2-desc');

  if (r1 && r1b && r1d) {
    r1.className = 'p-3.5 bg-slate-50 border border-slate-200/60 rounded-2xl flex flex-col justify-between h-[85px] transition-all';
    r1b.className = 'text-[9px] px-1.5 py-0.5 bg-emerald-50 text-emerald-600 font-bold rounded';
    r1b.textContent = 'Boş';
    r1d.className = 'text-[10px] text-slate-400 font-normal leading-normal';
    r1d.textContent = 'Müsait';
  }

  if (r2 && r2b && r2d) {
    r2.className = 'p-3.5 bg-slate-50 border border-slate-200/60 rounded-2xl flex flex-col justify-between h-[85px] transition-all';
    r2b.className = 'text-[9px] px-1.5 py-0.5 bg-emerald-50 text-emerald-600 font-bold rounded';
    r2b.textContent = 'Boş';
    r2d.className = 'text-[10px] text-slate-400 font-normal leading-normal';
    r2d.textContent = 'Müsait - Sadece Yetkili Terapistler';
  }
}

function updateSimConsole(message, colorClass) {
  const consoleEl = document.getElementById('sim-console');
  if (consoleEl) {
    consoleEl.innerHTML = `
      <span class='${colorClass} font-bold mb-1'>&gt; ${message}</span>
      <span class='text-slate-500'>Terapistlerin yetki durumlarını değiştirip simülasyonu çalıştırabilirsiniz.</span>
    `;
  }
}
